1	type Item = { type: string; material?: string; enchantment?: number; cursed?: boolean };
2	type Step = { op: "quote"; items: Item[] };
3	type Customer = { yearsWithMHPCO: number };
4	type Scenario = { customer: Customer; steps: Step[] };
5	
6	const PROCESSING_FEE = 5;
7	const FIRST_INSURANCE_RATE = 0.1;
8	
9	const BASE_PREMIUM_BY_TYPE: Record<string, number> = {
10	  sword: 100,
11	  amulet: 60,
12	  staff: 80,
13	  potion: 40,
14	  rune: 25,
15	  moonstone: 25,
16	};
17	
18	const basePremiumForType = (type: string): number => BASE_PREMIUM_BY_TYPE[type] ?? 0;
19	const itemBasePremium = (item: Item): number => basePremiumForType(item.type);
20	
21	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
22	const BLOCK_SIZE = 3;
23	const BLOCK_OF_THREE_BASE_PREMIUM = 60;
24	
25	const isComponent = (item: Item): boolean => COMPONENT_TYPES.has(item.type);
26	
27	const componentGroupPremium = (type: string, count: number): number =>
28	  count === BLOCK_SIZE ? BLOCK_OF_THREE_BASE_PREMIUM : count * basePremiumForType(type);
29	
30	const groupByType = (items: Item[]): Map<string, number> => {
31	  const counts = new Map<string, number>();
32	  for (const item of items) {
33	    counts.set(item.type, (counts.get(item.type) ?? 0) + 1);
34	  }
35	  return counts;
36	};
37	
38	const sum = (values: number[]): number => values.reduce((total, value) => total + value, 0);
39	
40	const policyBasePremium = (items: Item[]): number => {
41	  const mainItems = items.filter((item) => !isComponent(item));
42	  const componentItems = items.filter(isComponent);
43	  const componentCounts = groupByType(componentItems);
44	
45	  const mainTotal = sum(mainItems.map(itemBasePremium));
46	  const componentTotal = sum(
47	    [...componentCounts].map(([type, count]) => componentGroupPremium(type, count)),
48	  );
49	
50	  return mainTotal + componentTotal;
51	};
52	
53	const CURSE_SURCHARGE_RATE = 0.5;
54	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
55	const HIGH_ENCHANTMENT_THRESHOLD = 5;
56	
57	const itemSurcharges = (item: Item): number => {
58	  const base = itemBasePremium(item);
59	  const curse = item.cursed ? base * CURSE_SURCHARGE_RATE : 0;
60	  const highEnch =
61	    (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD
62	      ? base * HIGH_ENCHANTMENT_SURCHARGE_RATE
63	      : 0;
64	  return curse + highEnch;
65	};
66	
67	const LOYALTY_DISCOUNT_RATE = 0.2;
68	const LOYALTY_YEARS_THRESHOLD = 2;
69	const FOLLOWUP_DISCOUNT_RATE = 0.15;
70	
71	const quotePremium = (items: Item[], customer: Customer, isFollowUp: boolean): number => {
72	  const basePremium = policyBasePremium(items);
73	  const surcharges = sum(items.map(itemSurcharges));
74	  const loyaltyDiscount =
75	    customer.yearsWithMHPCO >= LOYALTY_YEARS_THRESHOLD ? basePremium * LOYALTY_DISCOUNT_RATE : 0;
76	  const followUpDiscount = isFollowUp ? basePremium * FOLLOWUP_DISCOUNT_RATE : 0;
77	  const firstInsurance = basePremium * FIRST_INSURANCE_RATE;
78	  const premiumBeforeFee = Math.ceil(
79	    basePremium + surcharges - loyaltyDiscount - followUpDiscount + firstInsurance,
80	  );
81	  return premiumBeforeFee + PROCESSING_FEE;
82	};
83	
84	export const runScenario = (scenario: Scenario): unknown => {
85	  let quoteCount = 0;
86	  const results = scenario.steps.map((step) => {
87	    const isFollowUp = quoteCount > 0;
88	    quoteCount += 1;
89	    return { premium: quotePremium(step.items, scenario.customer, isFollowUp) };
90	  });
91	  return { results };
92	};
